    <div class="custom-content">
        <header class="custom-top-banner">
            <nav class="custom-top-nav">
                <div class="nav-wrapper">
                    <div class="my-nav-menu">
                        <a href="/" class="nav-link">🏡 首页</a>
                        <a href="/blog-custom/" class="nav-link active">🗺️ 博客</a>
                        <a href="/custom-archives/" class="nav-link">🗄️ 归档</a>
                    </div>
                </div>
            </nav>
        </header>

        <div class="page-container">
            <!-- 分隔线区域 - 文字在上，虚线在下，左端对齐 -->
            <div class="divider-wrapper">
                <div class="divider-title">🌸发现</div>
                <div class="divider-line"></div>
            </div>

            <div class="page-layout">
                <main class="posts-column" id="posts-container">
                    <div class="loading-state">📚 加载文章中...</div>
                </main>
            </div>
        </div>
    </div>

    <script>
    (function() {
        const container = document.getElementById('posts-container');

        container.innerHTML = '<div class="loading-state">📚 加载文章中...</div>';

        fetch('/content.json?t=' + Date.now())
            .then(response => {
                if (!response.ok) throw new Error('content.json 不存在');
                return response.json();
            })
            .then(data => {
                let posts = Array.isArray(data) ? data : (data.posts || []);

                if (posts.length === 0) {
                    container.innerHTML = '<div class="empty-state">📭 暂无文章</div>';
                    return;
                }

                // ===== 颜色函数 =====
                const categoryColors = [
                    { bg: 'rgba(52, 152, 219, 0.15)', text: '#2980b9' },  // 技术 - 蓝色
                    { bg: 'rgba(46, 204, 113, 0.15)', text: '#27ae60' },  // 教程 - 绿色
                    { bg: 'rgba(155, 89, 182, 0.15)', text: '#8e44ad' },  // 设计 - 紫色
                    { bg: 'rgba(241, 196, 15, 0.15)', text: '#f39c12' },  // 随笔 - 橙色
                    { bg: 'rgba(231, 76, 60, 0.15)', text: '#c0392b' },   // 公告 - 红色
                    { bg: 'rgba(26, 188, 156, 0.15)', text: '#16a085' },  // 其他 - 青绿
                    { bg: 'rgba(52, 73, 94, 0.15)', text: '#2c3e50' },    // 其他 - 深蓝灰
                    { bg: 'rgba(243, 156, 18, 0.15)', text: '#d35400' },  // 其他 - 橙黄
                ];

                // 颜色缓存
                const colorCache = new Map();

                // 获取分类颜色样式
                function getCategoryStyle(category) {
                    if (!colorCache.has(category)) {
                        const index = colorCache.size % categoryColors.length;
                        colorCache.set(category, categoryColors[index]);
                    }
                    const color = colorCache.get(category);
                    return `background-color: ${color.bg}; color: ${color.text}; border-color: ${color.bg.replace('0.15', '0.3')};`;
                }
                // ===== 颜色函数结束 =====

                posts.sort((a, b) => new Date(b.date) - new Date(a.date));

                let html = '';
                posts.forEach(post => {
    let dateStr = '日期未知';
    try {
        const d = new Date(post.date);
        dateStr = `${d.getFullYear()}年${d.getMonth()+1}月${d.getDate()}日`;
    } catch(e) {}

    // ===== 处理所有分类 - 带链接版本 =====
    let categoriesHtml = '';
    if (post.categories && post.categories.length > 0) {
        categoriesHtml = post.categories.map(cat => {
            // 获取分类名称和slug
            let catName = '';
            let catSlug = '';

            if (typeof cat === 'string') {
                catName = cat;
                catSlug = cat;
            } else if (cat && typeof cat === 'object') {
                catName = cat.name || '';
                catSlug = cat.slug || cat.name || '';
            }

            if (!catName) return '';

            // 分类链接（Hexo默认格式）
            const categoryLink = `/categories/?cat=${encodeURIComponent(catName)}`;

            // 返回带链接的分类标签
            return `<a href="${categoryLink}" class="post-cat-link"><span class="post-cat" style="${getCategoryStyle(catName)}">${catName}</span></a>`;
        }).join('');
    }

    const postPath = post.path.startsWith('/') ? post.path : '/' + post.path;
    const link = `/post-template.html?path=${encodeURIComponent(postPath)}`;

    let excerpt = post.excerpt || post.content 
        ? (post.excerpt || post.content.replace(/<[^>]*>/g, '').substring(0, 120) + '…')
        : '';

    html += `
        <article class="post-card">
            <div class="post-image">
                <img src="${post.thumbnail || '/images/default-post.jpg'}" alt="${post.title}" loading="lazy">
            </div>
            <div class="post-content-wrapper">
                <div class="post-meta">
                    ${categoriesHtml}
                </div>
                <h2 class="post-title">
                    <a href="${link}">${post.title || '无标题'}</a>
                </h2>
                <p class="post-desc">${excerpt}</p>
            </div>
        </article>
    `;
});

                container.innerHTML = html;
            })
            .catch(error => {
                container.innerHTML = `
                    <div class="error-state">
                        <span style="font-size:1.5rem;">⚠️</span>
                        <h3 style="color:#b45309;">加载失败</h3>
                        <p>${error.message}</p>
                    </div>
                `;
            });
    })();
</script>
</body>
</html>

