                    html += `<h2 class="archive-year">${year}年</h2>`;
                    html += `<ul class="archive-list">`;
                    years[year].forEach(post => {
                        let date = new Date(post.date);
                        let dateStr = `${date.getMonth()+1}月${date.getDate()}日`;
                        html += `
                            <li class="archive-item">
                                <span class="archive-date">${dateStr}</span>
                                <span class="archive-title">
                                    <a href="${post.path}">${post.title}</a>
                                </span>
                            </li>
                        `;
                    });
                    html += `</ul>`;
                });

                document.getElementById('archive-container').innerHTML = html;
            })
            .catch(() => {
                document.getElementById('archive-container').innerHTML = '暂无文章';
            });
    </script>
</body>
</html>
